import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import axios from 'axios';
import SkillTag from '../components/SkillTag';
import MatchScore from '../components/MatchScore';

export default function ProjectDetail() {
  const { id } = useParams();
  const { user, API } = useAuth();
  const navigate = useNavigate();
  const [project, setProject] = useState(null);
  const [requests, setRequests] = useState([]);
  const [myRequest, setMyRequest] = useState(null);
  const [message, setMessage] = useState('');
  const [loading, setLoading] = useState(true);
  const [applying, setApplying] = useState(false);
  const [showApply, setShowApply] = useState(false);

  useEffect(() => {
    const load = async () => {
      try {
        const pRes = await axios.get(`${API}/projects/${id}`);
        setProject(pRes.data);
        if (user.role === 'staff' || user.role === 'admin') {
          const rRes = await axios.get(`${API}/requests/project/${id}`);
          setRequests(rRes.data);
        } else {
          const rRes = await axios.get(`${API}/requests/my`);
          const found = rRes.data.find(r => r.project?._id === id);
          setMyRequest(found || null);
        }
      } catch {}
      setLoading(false);
    };
    load();
  }, [id, API, user.role]);

  const calcMatch = (skills) => {
    if (!user.skills || !skills) return 0;
    const s = user.skills.map(x=>x.toLowerCase());
    const r = skills.map(x=>x.toLowerCase());
    const matched = r.filter(skill => s.some(ss => ss.includes(skill) || skill.includes(ss)));
    return r.length > 0 ? Math.round((matched.length / r.length) * 100) : 100;
  };

  const handleApply = async () => {
    if (!message.trim()) return alert('Please add a message');
    setApplying(true);
    try {
      await axios.post(`${API}/requests`, { projectId: id, message });
      alert('Application sent!');
      setShowApply(false);
      navigate('/requests');
    } catch (err) { alert(err.response?.data?.message || 'Failed'); }
    setApplying(false);
  };

  const handleRequest = async (reqId, status) => {
    try {
      await axios.put(`${API}/requests/${reqId}`, { status });
      const rRes = await axios.get(`${API}/requests/project/${id}`);
      setRequests(rRes.data);
      const pRes = await axios.get(`${API}/projects/${id}`);
      setProject(pRes.data);
    } catch (err) { alert(err.response?.data?.message || 'Failed'); }
  };

  if (loading) return <div style={{padding:'3rem',textAlign:'center',color:'#6c63ff'}}>Loading...</div>;
  if (!project) return <div style={{padding:'3rem',textAlign:'center',color:'#ff5757'}}>Project not found</div>;

  const match = user.role === 'student' ? calcMatch(project.requiredSkills) : null;

  return (
    <div style={{padding:'2rem',maxWidth:900,margin:'0 auto'}}>
      <button onClick={()=>navigate(-1)} style={{background:'transparent',border:'none',color:'#9aa3bf',cursor:'pointer',marginBottom:'1.5rem',fontSize:'0.9rem'}}>← Back</button>

      <div style={{background:'#161c2e',border:'1px solid #252d47',borderRadius:16,padding:'2rem',marginBottom:'1.5rem'}}>
        <div style={{display:'flex',justifyContent:'space-between',alignItems:'flex-start',marginBottom:'1rem'}}>
          <h1 style={{fontWeight:800,fontSize:'1.5rem',flex:1,marginRight:'1rem'}}>{project.title}</h1>
          <span style={{background:project.status==='open'?'rgba(0,212,170,0.15)':'rgba(255,87,87,0.15)',color:project.status==='open'?'#00d4aa':'#ff5757',border:`1px solid ${project.status==='open'?'#00d4aa40':'#ff575740'}`,borderRadius:99,padding:'4px 14px',fontWeight:600}}>
            {project.status}
          </span>
        </div>

        <div style={{display:'flex',alignItems:'center',gap:'10px',marginBottom:'1rem'}}>
          <div style={{width:40,height:40,borderRadius:'50%',background:'linear-gradient(135deg, #6c63ff, #ff6b9d)',display:'flex',alignItems:'center',justifyContent:'center',color:'#fff',fontWeight:700,fontSize:'0.85rem'}}>
            {project.faculty?.name?.split(' ').map(n=>n[0]).join('').slice(0,2)}
          </div>
          <div>
            <div style={{fontWeight:600}}>{project.faculty?.name}</div>
            <div style={{color:'#9aa3bf',fontSize:'0.875rem'}}>{project.faculty?.department} · {project.faculty?.designation}</div>
          </div>
        </div>

        <p style={{color:'#9aa3bf',lineHeight:1.7,marginBottom:'1.5rem'}}>{project.description}</p>

        <div style={{display:'grid',gridTemplateColumns:'repeat(3, 1fr)',gap:'1rem',marginBottom:'1.5rem'}}>
          {[
            {label:'Max Students',value:`${project.acceptedStudents?.length || 0}/${project.maxStudents}`},
            {label:'Duration',value:project.duration || 'Not specified'},
            {label:'Stipend',value:project.stipend || 'Not specified'},
          ].map(item => (
            <div key={item.label} style={{background:'#0f1320',borderRadius:10,padding:'0.75rem 1rem'}}>
              <div style={{color:'#5c6580',fontSize:'0.75rem',marginBottom:'0.25rem'}}>{item.label}</div>
              <div style={{fontWeight:600,fontSize:'0.9rem',fontFamily:'Space Mono, monospace',color:'#e8eaf0'}}>{item.value}</div>
            </div>
          ))}
        </div>

        {project.prerequisites && (
          <div style={{background:'rgba(255,179,71,0.08)',border:'1px solid rgba(255,179,71,0.2)',borderRadius:10,padding:'0.75rem 1rem',marginBottom:'1rem'}}>
            <div style={{color:'#ffb347',fontSize:'0.8rem',fontWeight:600,marginBottom:'0.25rem'}}>Prerequisites</div>
            <div style={{fontSize:'0.875rem',color:'#e8eaf0'}}>{project.prerequisites}</div>
          </div>
        )}

        <div style={{marginBottom:'1rem'}}>
          <div style={{color:'#5c6580',fontSize:'0.8rem',marginBottom:'0.5rem',fontWeight:600}}>REQUIRED SKILLS</div>
          <div style={{display:'flex',gap:'0.5rem',flexWrap:'wrap'}}>
            {project.requiredSkills?.map(s=><SkillTag key={s} skill={s} size="lg" />)}
          </div>
        </div>

        {match !== null && (
          <div style={{background:'#0f1320',borderRadius:10,padding:'1rem',marginBottom:'1rem'}}>
            <div style={{color:'#9aa3bf',fontSize:'0.8rem',marginBottom:'0.5rem',fontWeight:600}}>YOUR SKILL MATCH</div>
            <MatchScore score={match} />
          </div>
        )}

        {user.role === 'student' && project.status === 'open' && (
          myRequest ? (
            <div style={{background:myRequest.status==='accepted'?'rgba(74,222,128,0.1)':myRequest.status==='rejected'?'rgba(255,87,87,0.1)':'rgba(255,179,71,0.1)',border:`1px solid ${myRequest.status==='accepted'?'#4ade8040':myRequest.status==='rejected'?'#ff575740':'#ffb34740'}`,borderRadius:10,padding:'1rem'}}>
              <div style={{fontWeight:600,color:myRequest.status==='accepted'?'#4ade80':myRequest.status==='rejected'?'#ff5757':'#ffb347',marginBottom:'0.25rem'}}>
                Application Status: {myRequest.status.toUpperCase()}
              </div>
              {myRequest.facultyNote && <div style={{color:'#9aa3bf',fontSize:'0.875rem'}}>Note: {myRequest.facultyNote}</div>}
            </div>
          ) : (
            <button onClick={()=>setShowApply(true)} style={{padding:'12px 28px',background:'linear-gradient(135deg, #6c63ff, #8b85ff)',border:'none',borderRadius:10,color:'#fff',fontWeight:700,cursor:'pointer',fontSize:'0.95rem'}}>
              Apply for this Project
            </button>
          )
        )}
      </div>

      {(user.role === 'staff' || user.role === 'admin') && requests.length > 0 && (
        <div>
          <h2 style={{fontWeight:700,marginBottom:'1rem'}}>Applications ({requests.length})</h2>
          {requests.map(r => (
            <div key={r._id} style={{background:'#161c2e',border:'1px solid #252d47',borderRadius:14,padding:'1.25rem',marginBottom:'1rem'}}>
              <div style={{display:'flex',justifyContent:'space-between',alignItems:'flex-start',marginBottom:'0.75rem'}}>
                <div>
                  <div style={{fontWeight:700,fontSize:'1rem'}}>{r.student?.name}</div>
                  <div style={{color:'#9aa3bf',fontSize:'0.8rem'}}>{r.student?.department} · {r.student?.year} · GPA: {r.student?.gpa || 'N/A'}</div>
                </div>
                <div style={{display:'flex',alignItems:'center',gap:'1rem'}}>
                  <div style={{fontFamily:'Space Mono',fontWeight:700,color:r.skillMatchScore>=70?'#4ade80':r.skillMatchScore>=40?'#ffb347':'#ff5757'}}>{r.skillMatchScore}% match</div>
                  {r.status !== 'pending' && (
                    <span style={{padding:'3px 12px',borderRadius:99,fontSize:'0.75rem',fontWeight:600,background:r.status==='accepted'?'rgba(74,222,128,0.15)':'rgba(255,87,87,0.15)',color:r.status==='accepted'?'#4ade80':'#ff5757'}}>{r.status}</span>
                  )}
                </div>
              </div>
              <div style={{display:'flex',gap:'0.4rem',flexWrap:'wrap',marginBottom:'0.75rem'}}>
                {r.student?.skills?.map(s=><SkillTag key={s} skill={s} />)}
              </div>
              <div style={{background:'#0f1320',borderRadius:8,padding:'0.75rem',marginBottom:'0.75rem',color:'#9aa3bf',fontSize:'0.875rem',fontStyle:'italic'}}>"{r.message}"</div>
              <div style={{display:'flex',gap:'0.5rem'}}>
                {r.student?.github && <a href={r.student.github} target="_blank" rel="noreferrer" style={{padding:'6px 14px',borderRadius:8,border:'1px solid #252d47',color:'#9aa3bf',fontSize:'0.8rem',textDecoration:'none'}}>GitHub</a>}
                {r.student?.portfolio && <a href={r.student.portfolio} target="_blank" rel="noreferrer" style={{padding:'6px 14px',borderRadius:8,border:'1px solid #252d47',color:'#9aa3bf',fontSize:'0.8rem',textDecoration:'none'}}>Portfolio</a>}
                {r.status === 'pending' && (
                  <>
                    <button onClick={()=>handleRequest(r._id,'accepted')} style={{padding:'6px 16px',borderRadius:8,background:'rgba(74,222,128,0.1)',border:'1px solid #4ade8040',color:'#4ade80',fontWeight:600,cursor:'pointer',fontSize:'0.85rem'}}>✓ Accept</button>
                    <button onClick={()=>handleRequest(r._id,'rejected')} style={{padding:'6px 16px',borderRadius:8,background:'rgba(255,87,87,0.1)',border:'1px solid #ff575740',color:'#ff5757',fontWeight:600,cursor:'pointer',fontSize:'0.85rem'}}>✗ Reject</button>
                  </>
                )}
              </div>
            </div>
          ))}
        </div>
      )}

      {showApply && (
        <div style={{position:'fixed',inset:0,background:'rgba(0,0,0,0.7)',display:'flex',alignItems:'center',justifyContent:'center',zIndex:1000,padding:'1rem'}}>
          <div style={{background:'#161c2e',border:'1px solid #252d47',borderRadius:16,padding:'2rem',width:'100%',maxWidth:480}}>
            <h2 style={{fontWeight:800,marginBottom:'0.5rem'}}>Apply for Project</h2>
            <p style={{color:'#9aa3bf',fontSize:'0.875rem',marginBottom:'1.5rem'}}>{project.title}</p>
            <div style={{marginBottom:'1rem'}}>
              <label style={{display:'block',marginBottom:'6px',fontSize:'0.875rem',fontWeight:600,color:'#9aa3bf'}}>Your Message *</label>
              <textarea value={message} onChange={e=>setMessage(e.target.value)} placeholder="Tell the professor why you're interested, your relevant experience, what you hope to contribute..." rows={5} style={{width:'100%',padding:'12px',background:'#0f1320',border:'1px solid #252d47',borderRadius:10,color:'#e8eaf0',fontSize:'0.9rem',outline:'none',resize:'vertical'}} />
            </div>
            <div style={{display:'flex',gap:'0.75rem'}}>
              <button onClick={()=>setShowApply(false)} style={{flex:1,padding:'12px',background:'transparent',border:'1px solid #252d47',borderRadius:10,color:'#9aa3bf',fontWeight:600,cursor:'pointer'}}>Cancel</button>
              <button onClick={handleApply} disabled={applying} style={{flex:2,padding:'12px',background:'linear-gradient(135deg, #6c63ff, #8b85ff)',border:'none',borderRadius:10,color:'#fff',fontWeight:700,cursor:'pointer'}}>{applying?'Sending...':'Send Application'}</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
